/destinations.get:
import { Celitech } from 'celitech-sdk';

(async () => {
  const celitech = new Celitech({
	clientId: 'CLIENT_ID',
	clientSecret: 'CLIENT_SECRET',
});

  const data = await celitech.destinations.listDestinations({
      accept: "application/json",
  });

  console.log(data);
})();

